VALUES
  ('optometrist-moex-03344', 'optometrist', 'optometrist-moex-106-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '採用視網膜檢影鏡且使用工作輔助鏡片時，檢影鏡光束線條放在90度時測得-4.50 D，檢影鏡光束線條放 在180度時測得-2.50 D，則患者的矯正度數為何？', '["-2.50DS /-2.00DC×180", "-3.50DS/-2.00DC×090", "-3.50DS/-2.50DC×180", "-2.50DS/-2.00DC×090"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "d48b9e09da91", "answer_pdf_sha1": "3dd3238e5460", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03345', 'optometrist', 'optometrist-moex-106-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '紅綠雙色試驗中，紅色背景的視標比較清楚，表示：', '["矯正後的聚焦點在視網膜前方，應增加凸透鏡度數或減少凹透鏡度數", "矯正後的聚焦點在視網膜前方，應減少凸透鏡度數或增加凹透鏡度數", "矯正後的聚焦點在視網膜後方，應增加凸透鏡度數或減少凹透鏡度數", "矯正後的聚焦點在視網膜後方，應減少凸透鏡度數或增加凹透鏡度數"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "d48b9e09da91", "answer_pdf_sha1": "3dd3238e5460", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03346', 'optometrist', 'optometrist-moex-106-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '電腦驗光結果是-1.00DS/-1.50DC×110，利用交叉圓柱鏡（cross cylinder）驗證散光時，需加上何種鏡片， 讓影像在眼內聚焦形成的兩條焦線，且此兩條焦線應投射在何處再用交叉圓柱鏡檢驗為較佳之選擇？', '["用球面鏡片，使影像形成的兩條焦線投射在視網膜上及視網膜之前", "用球面鏡片，使影像形成的兩條焦線投射在視網膜上及視網膜之後", "用球面鏡片，使影像形成的兩條焦線投射在視網膜之前及視網膜之後", "同時用球面鏡片及散光鏡片，使影像形成的兩條焦線投射在視網膜之前及視網膜之後"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "d48b9e09da91", "answer_pdf_sha1": "3dd3238e5460", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03347', 'optometrist', 'optometrist-moex-106-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '電腦驗光結果是+2.00DS/-1.00DC×060，利用散光圖形表（astigmatic dial）檢驗散光時，先加上何種鏡片， 讓影像在眼內聚焦形成的兩條焦線，投射在何處再看散光圖形較準確？', '["用球面鏡片，使影像形成的兩條焦線投射在視網膜之前或視網膜上", "用球面鏡片，使影像形成的兩條焦線投射在視網膜之後或視網膜上", "用球面鏡片，使影像形成的兩條焦線投射在視網膜之前及視網膜之後", "同時用球面鏡片及散光鏡片，使影像形成的兩條焦線投射在視網膜之前及視網膜之後"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "d48b9e09da91", "answer_pdf_sha1": "3dd3238e5460", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03348', 'optometrist', 'optometrist-moex-106-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '正視眼前加上交叉圓柱鏡，白點位於水平方向，則：', '["水平方向的光線，聚焦在視網膜之前，形成一條水平焦線", "水平方向的光線，聚焦在視網膜之前，形成一條垂直焦線", "水平方向的光線，聚焦在視網膜之後，形成一條水平焦線", "水平方向的光線，聚焦在視網膜之後，形成一條垂直焦線"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "d48b9e09da91", "answer_pdf_sha1": "3dd3238e5460", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03349', 'optometrist', 'optometrist-moex-106-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '配戴有散光度數的眼鏡時，如果完全矯正後，受檢者戴上眼鏡有不適應的狀況，下列敘述何者錯誤？', '["減少圓柱透鏡度數，同時增加球面透鏡度數，可以改善調整後視力模糊的情況", "調整圓柱透鏡的角度到接近原來眼鏡的散光角度，可以減輕不適應感覺", "調整圓柱透鏡的角度到接近垂直方向或水平方向，可以減輕不適應感覺", "調整圓柱透鏡的角度，同時增加圓柱透鏡的度數，可以改善調整後視力模糊的情況"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "d48b9e09da91", "answer_pdf_sha1": "3dd3238e5460", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03350', 'optometrist', 'optometrist-moex-106-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '利用時鐘刻度表示的散光圖形表，如果適當的霧視後，受檢者指出兩點鐘到三點鐘中間的線條最明顯， 顏色最深。以負圓柱透鏡矯正時，矯正軸度應放置於：', '["15度", "75度", "105度", "165度"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "d48b9e09da91", "answer_pdf_sha1": "3dd3238e5460", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03351', 'optometrist', 'optometrist-moex-106-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '關於進行雙眼平衡檢測（binocular balance procedure）之目的，下列何者正確？', '["讓雙眼瞳孔大小達到平衡", "讓雙眼視力達到平衡", "讓雙眼眼外肌達到平衡", "讓雙眼調節達到平衡"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "d48b9e09da91", "answer_pdf_sha1": "3dd3238e5460", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-03352', 'optometrist', 'optometrist-moex-106-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '受檢者的遠點在眼球後方100公分處，看眼前近距離25公分處的視標，需要多少調節力？', '["1.00 D", "3.00 D", "4.00 D", "5.00 D"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:55+00:00", "source_pdf_sha1": "d48b9e09da91", "answer_pdf_sha1": "3dd3238e5460", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
